const body = $input.first().json.body || $input.first().json;
const typeLabel = { 'facture': 'Facture', 'devis': 'Devis', 'bon_livraison': 'Bon de Livraison', 'bon_commande': 'Bon de Commande', 'avoir': 'Avoir' }[body.type_document] || body.type_document || 'Document';
const montantHT = body.montant_ht ? Number(body.montant_ht).toFixed(3) + ' TND' : 'N/A';
const montantTTC = body.montant_ttc ? Number(body.montant_ttc).toFixed(3) + ' TND' : 'N/A';
const confiance = body.score_confiance ? Math.round(body.score_confiance * 100) + '%' : 'N/A';
const subject = '[SPARKY] ' + typeLabel + ' scanne - ' + (body.fournisseur || 'Fournisseur inconnu');

// Tableau des articles
const lignes = body.lignes || [];
let articlesTable = '';
if (lignes.length > 0) {
  const rows = lignes.map((l, i) => {
    const pu = Number(l.prix_unitaire || 0).toFixed(3);
    const qte = Number(l.quantite || 1);
    const rem = Number(l.remise || 0);
    const tva = Number(l.tva || 0);
    const ttc = Number(l.montant_ttc || 0).toFixed(3);
    return '<tr style="background:' + (i%2===0?'#fff':'#f8f9ff') + '">'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;font-weight:600;color:#1a1a2e">' + (l.designation || 'N/A') + '</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;font-family:monospace;font-size:12px;color:#1565c0">' + (l.reference || '-') + '</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;text-align:center">' + qte + '</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;text-align:right">' + pu + ' TND</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;text-align:center">' + (rem > 0 ? rem + '%' : '-') + '</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;text-align:center">' + (tva > 0 ? tva + '%' : '-') + '</td>'
      + '<td style="padding:9px 12px;border:1px solid #e0e0e0;text-align:right;font-weight:700;color:#1a1a2e">' + ttc + ' TND</td>'
      + '</tr>';
  }).join('');
  articlesTable = '<h3 style="color:#1a1a2e;font-size:15px;margin:24px 0 12px">Articles extraits (' + lignes.length + ')</h3>'
    + '<table style="width:100%;border-collapse:collapse;font-size:12px">'
    + '<thead><tr style="background:#1a1a2e">'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:left;border:1px solid #333">Designation</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:left;border:1px solid #333">Reference</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:center;border:1px solid #333">Qte</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:right;border:1px solid #333">Prix U.</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:center;border:1px solid #333">Rem.</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:center;border:1px solid #333">TVA</th>'
    + '<th style="padding:10px 12px;color:#f5c518;text-align:right;border:1px solid #333">TTC</th>'
    + '</tr></thead><tbody>' + rows + '</tbody>'
    + '<tfoot><tr style="background:#f0f4ff">'
    + '<td colspan="6" style="padding:10px 12px;font-weight:700;color:#1a1a2e;border:1px solid #e0e0e0">TOTAL TTC</td>'
    + '<td style="padding:10px 12px;font-weight:800;font-size:15px;color:#1a1a2e;text-align:right;border:1px solid #e0e0e0">' + montantTTC + '</td>'
    + '</tr></tfoot></table>';
} else {
  articlesTable = '<p style="color:#888;font-style:italic;margin:16px 0">Aucun article extrait pour ce document.</p>';
}

const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto">'
  + '<div style="background:#1a1a2e;padding:24px;border-radius:12px 12px 0 0;text-align:center">'
  + '<h1 style="color:#f5c518;margin:0;font-size:26px">SPARKY</h1>'
  + '<p style="color:rgba(255,255,255,.6);margin:4px 0 0;font-size:13px">Nouveau document scanne</p>'
  + '</div>'
  + '<div style="background:#fff;padding:28px;border:1px solid #e0e0e0">'
  + '<table style="width:100%;border-collapse:collapse;margin-bottom:8px">'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px;width:140px">Type</td><td style="padding:10px 0;font-weight:700;color:#1a1a2e">' + typeLabel + '</td></tr>'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px">Fichier</td><td style="padding:10px 0;color:#555">' + (body.nom_fichier || 'N/A') + '</td></tr>'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px">Fournisseur</td><td style="padding:10px 0;font-weight:700;color:#1a1a2e">' + (body.fournisseur || 'N/A') + '</td></tr>'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px">Numero</td><td style="padding:10px 0;font-family:monospace;color:#1565c0">' + (body.numero_document || 'N/A') + '</td></tr>'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px">Montant HT</td><td style="padding:10px 0;font-weight:700;color:#555">' + montantHT + '</td></tr>'
  + '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:10px 0;color:#888;font-size:13px">Montant TTC</td><td style="padding:10px 0;font-size:20px;font-weight:800;color:#1a1a2e">' + montantTTC + '</td></tr>'
  + '<tr><td style="padding:10px 0;color:#888;font-size:13px">Confiance OCR</td><td style="padding:10px 0;font-weight:700;color:#1565c0">' + confiance + '</td></tr>'
  + '</table>'
  + articlesTable
  + '</div>'
  + '<div style="background:#f5f5f5;padding:16px;border-radius:0 0 12px 12px;text-align:center">'
  + '<p style="margin:0;color:#aaa;font-size:12px">SPARKY v1.0 - ' + new Date().toLocaleString('fr-TN') + '</p>'
  + '</div></div>';
return [{ json: { subject, htmlBody } }];

const articles = Array.isArray($input.first().json) ? $input.first().json : [];
const total = articles.reduce((acc, a) => acc + (Number(a.quantite_stock||0) * Number(a.prix_unitaire||0)), 0);
const date = new Date().toLocaleDateString('fr-FR', {weekday:'long',year:'numeric',month:'long',day:'numeric'});
const rows = articles.slice(0,20).map((a,i) => '<tr style="background:' + (i%2===0?'#fff':'#f9f9f9') + '"><td style="padding:8px 12px;border:1px solid #e0e0e0;font-weight:600">' + (a.designation||a.nom||'N/A') + '</td><td style="padding:8px 12px;border:1px solid #e0e0e0;font-family:monospace;font-size:12px;color:#1565c0">' + (a.reference||'N/A') + '</td><td style="padding:8px 12px;border:1px solid #e0e0e0;text-align:right">' + (a.quantite_stock||0) + '</td><td style="padding:8px 12px;border:1px solid #e0e0e0;text-align:right;font-weight:700">' + Number(a.prix_unitaire||0).toFixed(3) + ' TND</td></tr>').join('');
const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto"><div style="background:#1a1a2e;padding:24px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#f5c518;margin:0">SPARKY</h1><p style="color:rgba(255,255,255,.6);margin:4px 0 0">Rapport Quotidien - ' + date + '</p></div><div style="background:#fff;padding:28px;border:1px solid #e0e0e0"><h2 style="color:#1a1a2e;margin:0 0 20px">Tableau de bord</h2><div style="display:flex;gap:16px;margin-bottom:24px"><div style="flex:1;background:#f0f4ff;border-radius:10px;padding:16px;border-left:4px solid #1565c0"><p style="margin:0;font-size:11px;color:#888;font-weight:700;text-transform:uppercase">Articles en stock</p><p style="margin:8px 0 0;font-size:28px;font-weight:800;color:#1565c0">' + articles.length + '</p></div><div style="flex:1;background:#e8f5e9;border-radius:10px;padding:16px;border-left:4px solid #388e3c"><p style="margin:0;font-size:11px;color:#888;font-weight:700;text-transform:uppercase">Valeur estimee</p><p style="margin:8px 0 0;font-size:22px;font-weight:800;color:#2e7d32">' + total.toFixed(3) + ' TND</p></div></div><table style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr style="background:#1a1a2e"><th style="padding:10px 12px;color:#f5c518;text-align:left;border:1px solid #333">Designation</th><th style="padding:10px 12px;color:#f5c518;text-align:left;border:1px solid #333">Reference</th><th style="padding:10px 12px;color:#f5c518;text-align:right;border:1px solid #333">Qte</th><th style="padding:10px 12px;color:#f5c518;text-align:right;border:1px solid #333">Prix</th></tr></thead><tbody>' + rows + '</tbody></table></div><div style="background:#f5f5f5;padding:16px;border-radius:0 0 12px 12px;text-align:center"><p style="margin:0;color:#aaa;font-size:12px">Genere par SPARKY n8n</p></div></div>';
return [{ json: { htmlBody, nb: articles.length } }];

const data = $input.first().json;
const articles = data.articles || [];
if (articles.length === 0) return [{ json: { skip: true, htmlBody: '', subject: '' } }];
const fournisseurs = (articles[0]?.prix_par_fournisseur || []).map(p => p.fournisseur || 'N/A');
const headers = fournisseurs.map(f => '<th style="padding:10px 12px;background:#1a1a2e;color:#f5c518;border:1px solid #333">' + f + '</th>').join('');
const rows = articles.map(art => { const prix = art.prix_par_fournisseur || []; const minPrix = prix.length > 0 ? Math.min(...prix.map(p => Number(p.prix_unitaire)||Infinity)) : null; const cellules = prix.map(p => { const pu = Number(p.prix_unitaire)||0; const best = minPrix !== null && Math.abs(pu-minPrix) < 0.001; return '<td style="padding:8px 12px;border:1px solid #e0e0e0;' + (best ? 'background:#e8f5e9;color:#2e7d32;font-weight:700' : 'color:#333') + '">' + pu.toFixed(3) + ' TND' + (best ? ' [V]' : '') + '</td>'; }).join(''); return '<tr><td style="padding:8px 12px;border:1px solid #e0e0e0;font-weight:600">' + (art.designation||'N/A') + '</td>' + cellules + '</tr>'; }).join('');
const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto"><div style="background:#1a1a2e;padding:24px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#f5c518;margin:0">SPARKY</h1><p style="color:rgba(255,255,255,.6);margin:4px 0 0">Comparaison des Prix Fournisseurs</p></div><div style="background:#fff;padding:28px;border:1px solid #e0e0e0"><p style="color:#555;font-size:13px;margin:0 0 16px">[V] = meilleur prix pour cet article</p><table style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr><th style="padding:10px 12px;background:#1a1a2e;color:#f5c518;text-align:left;border:1px solid #333">Article</th>' + headers + '</tr></thead><tbody>' + rows + '</tbody></table></div><div style="background:#f5f5f5;padding:16px;border-radius:0 0 12px 12px;text-align:center"><p style="margin:0;color:#aaa;font-size:12px">Genere par SPARKY n8n</p></div></div>';
return [{ json: { htmlBody, skip: false, subject: '[SPARKY] Comparaison prix - ' + new Date().toLocaleDateString('fr-FR') } }];

const data = $input.first().json;
const articles = data.articles || [];
const opportunites = [];
for (const art of articles) { const fx = (art.prix_par_fournisseur||[]).filter(p => Number(p.prix_unitaire)>0); if (fx.length < 2) continue; const sorted = [...fx].sort((a,b) => Number(a.prix_unitaire)-Number(b.prix_unitaire)); const best = sorted[0]; const worst = sorted[sorted.length-1]; const eco = Number(worst.prix_unitaire) - Number(best.prix_unitaire); if (eco > 0.001) { opportunites.push({ designation: art.designation||'N/A', meilleur: best.fournisseur, best_prix: Number(best.prix_unitaire).toFixed(3), pire: worst.fournisseur, pire_prix: Number(worst.prix_unitaire).toFixed(3), pct: ((eco/Number(worst.prix_unitaire))*100).toFixed(1), eco_totale: (eco*Number(art.quantite_stock||1)).toFixed(3) }); } }
if (opportunites.length === 0) return [{ json: { skip: true, htmlBody: '', subject: '' } }];
const total = opportunites.reduce((acc,o) => acc+Number(o.eco_totale), 0).toFixed(3);
const rows = opportunites.map((o,i) => '<tr style="background:' + (i%2===0?'#fff':'#f9f9f9') + '"><td style="padding:10px 12px;border:1px solid #e0e0e0;font-weight:600">' + o.designation + '</td><td style="padding:10px 12px;border:1px solid #e0e0e0;background:#e8f5e9"><strong style="color:#2e7d32">' + o.meilleur + '</strong><br><span style="font-weight:800">' + o.best_prix + ' TND</span></td><td style="padding:10px 12px;border:1px solid #e0e0e0;background:#ffebee"><span style="color:#b71c1c">' + o.pire + '</span><br><span>' + o.pire_prix + ' TND</span></td><td style="padding:10px 12px;border:1px solid #e0e0e0;text-align:center"><span style="background:#f57c00;color:#fff;padding:2px 8px;border-radius:10px;font-size:12px;font-weight:700">-' + o.pct + '%</span></td><td style="padding:10px 12px;border:1px solid #e0e0e0;text-align:right;font-weight:700;color:#2e7d32">' + o.eco_totale + ' TND</td></tr>').join('');
const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto"><div style="background:#1a1a2e;padding:24px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#f5c518;margin:0">SPARKY</h1><p style="color:rgba(255,255,255,.6);margin:4px 0 0">Alerte Meilleur Prix</p></div><div style="background:#fff;padding:28px;border:1px solid #e0e0e0"><div style="background:#e8f5e9;border-radius:10px;padding:16px;border-left:4px solid #388e3c;margin-bottom:20px"><h2 style="margin:0 0 8px;color:#1b5e20">' + opportunites.length + ' opportunite(s) d economie</h2><p style="margin:0;color:#2e7d32;font-size:15px">Economie potentielle : <strong>' + total + ' TND</strong></p></div><table style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr style="background:#1a1a2e"><th style="padding:10px 12px;color:#f5c518;text-align:left;border:1px solid #333">Article</th><th style="padding:10px 12px;color:#f5c518;border:1px solid #333">Meilleur Prix</th><th style="padding:10px 12px;color:#f5c518;border:1px solid #333">Prix Actuel</th><th style="padding:10px 12px;color:#f5c518;text-align:center;border:1px solid #333">Ecart</th><th style="padding:10px 12px;color:#f5c518;text-align:right;border:1px solid #333">Economie</th></tr></thead><tbody>' + rows + '</tbody><tfoot><tr><td colspan="4" style="padding:12px;font-weight:700;border:1px solid #e0e0e0">TOTAL ECONOMIES</td><td style="padding:12px;font-weight:800;color:#2e7d32;font-size:16px;text-align:right;border:1px solid #e0e0e0">' + total + ' TND</td></tr></tfoot></table></div><div style="background:#f5f5f5;padding:16px;border-radius:0 0 12px 12px;text-align:center"><p style="margin:0;color:#aaa;font-size:12px">Genere par SPARKY n8n</p></div></div>';
return [{ json: { htmlBody, skip: false, subject: '[SPARKY] Alerte prix - ' + opportunites.length + ' opportunite(s) - ' + total + ' TND d economie' } }];
